return [
  {
    json: {
      ...items[0].json,
      ...items[1].json,
      ...items[2].json,
    },
    binary: {
      file1: items[0].binary.data,
      file2: items[1].binary.data,
      file3: items[2].binary.data
    }
  }
];

return items.map(item => {
  const body = item.json.body;

  const dateEntree = new Date(body.date_entree);
  const dateSortie = new Date(body.date_sortie);

  if (isNaN(dateEntree) || isNaN(dateSortie)) {
    throw new Error("Date invalide détectée : " + JSON.stringify(body));
  }

  dateEntree.setDate(dateEntree.getDate() + 1);
  dateSortie.setDate(dateSortie.getDate() + 1);

  body.date_entree = dateEntree.toISOString().split('T')[0];
  body.date_sortie = dateSortie.toISOString().split('T')[0];

  item.json.body = body;
  return item;
});

